import{_ as e,o as a,c as r,a2 as d}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"Unit Role Matrix","description":"","frontmatter":{},"headers":[],"relativePath":"warfare/unit-roles.md","filePath":"warfare/unit-roles.md","lastUpdated":null}'),i={name:"warfare/unit-roles.md"};function o(n,t,l,s,c,h){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="unit-role-matrix" tabindex="-1">Unit Role Matrix <a class="header-anchor" href="#unit-role-matrix" aria-label="Permalink to &quot;Unit Role Matrix&quot;">​</a></h1><p>Every faction in the Warfare domain fills the same 13 role slots with theme-appropriate units. This ensures mechanical balance while allowing visual/audio theming.</p><h2 id="the-13-required-roles" tabindex="-1">The 13 Required Roles <a class="header-anchor" href="#the-13-required-roles" aria-label="Permalink to &quot;The 13 Required Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>Slot</th><th>Tier</th><th>Description</th></tr></thead><tbody><tr><td>1</td><td>T1 Cheap</td><td>1</td><td>Expendable early-game unit, low cost, low stats</td></tr><tr><td>2</td><td>T1 Core</td><td>1</td><td>Main line infantry, backbone of the army</td></tr><tr><td>3</td><td>T2 Elite</td><td>2</td><td>Premium infantry, high damage/survivability</td></tr><tr><td>4</td><td>T2 Anti-Armor</td><td>2</td><td>Specialized anti-vehicle/heavy unit</td></tr><tr><td>5</td><td>T2 Support</td><td>2</td><td>Suppression/support fire, MG equivalent</td></tr><tr><td>6</td><td>T2 Recon</td><td>2</td><td>Scout/reconnaissance, fast and fragile</td></tr><tr><td>7</td><td>T3 Light Vehicle</td><td>3</td><td>Fast vehicle, flanking and pursuit</td></tr><tr><td>8</td><td>T3 Heavy Vehicle</td><td>3</td><td>Main battle tank or heavy walker</td></tr><tr><td>9</td><td>T3 Artillery</td><td>3</td><td>Long-range bombardment</td></tr><tr><td>10</td><td>Defense 1</td><td>—</td><td>Light static defense (MG nest, tower)</td></tr><tr><td>11</td><td>Defense 2</td><td>—</td><td>Heavy static defense (AT, missile)</td></tr><tr><td>12</td><td>Commander</td><td>—</td><td>Hero/command unit with buffs</td></tr><tr><td>13</td><td>Spike Unit</td><td>—</td><td>Faction signature unit, unique capability</td></tr></tbody></table><h2 id="full-faction-matrix" tabindex="-1">Full Faction Matrix <a class="header-anchor" href="#full-faction-matrix" aria-label="Permalink to &quot;Full Faction Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Slot</th><th>Republic</th><th>CIS</th><th>West</th><th>Classic Enemy</th><th>Guerrilla</th></tr></thead><tbody><tr><td>T1 Cheap</td><td>Militia clone</td><td>B1</td><td>Militia</td><td>Conscript</td><td>Irregular</td></tr><tr><td>T1 Core</td><td>Clone trooper</td><td>B1 improved / B2</td><td>Rifle squad</td><td>Rifle infantry</td><td>Raider rifle</td></tr><tr><td>T2 Elite</td><td>ARC trooper</td><td>Commando droid</td><td>Spec ops</td><td>Guards / assault</td><td>Veteran cell</td></tr><tr><td>T2 Anti-Armor</td><td>Clone AT</td><td>Heavy droid AT</td><td>ATGM team</td><td>AT team</td><td>RPG team</td></tr><tr><td>T2 Support</td><td>Repeater team</td><td>Heavy blaster</td><td>MG team</td><td>MG team</td><td>HMG / recoilless</td></tr><tr><td>T2 Recon</td><td>Scout trooper</td><td>Commando scout</td><td>Drone recon</td><td>Scout / mech recon</td><td>Infiltrator</td></tr><tr><td>T3 Light Vehicle</td><td>AT-RT / speeder</td><td>Dwarf / spider</td><td>Technical / IFV</td><td>IFV</td><td>Technical</td></tr><tr><td>T3 Heavy Vehicle</td><td>Walker / tank</td><td>AAT / heavy droid</td><td>MBT</td><td>MBT / assault gun</td><td><em>(N/A)</em></td></tr><tr><td>T3 Artillery</td><td>SP battery</td><td>Shelling droid</td><td>MLRS / howitzer</td><td>Tube + rocket arty</td><td>Mortar / rocket</td></tr><tr><td>Defense 1</td><td>Blaster tower</td><td>Droid tower</td><td>MG nest</td><td>Bunker</td><td>Fortified nest</td></tr><tr><td>Defense 2</td><td>Heavy laser</td><td>Shielded turret</td><td>AT / missile</td><td>Heavy missile</td><td>Rocket emplacement</td></tr><tr><td>Commander</td><td>Jedi / clone cmdr</td><td>Tactical relay</td><td>Officer / UAV</td><td>Commissar / cmd</td><td>Field emir</td></tr><tr><td>Spike Unit</td><td>Shield elite</td><td>Droideka</td><td>Drone strike</td><td>Thermobaric</td><td>Ambush wave</td></tr></tbody></table><h2 id="role-details" tabindex="-1">Role Details <a class="header-anchor" href="#role-details" aria-label="Permalink to &quot;Role Details&quot;">​</a></h2><h3 id="t1-cheap-expendable" tabindex="-1">T1 Cheap (Expendable) <a class="header-anchor" href="#t1-cheap-expendable" aria-label="Permalink to &quot;T1 Cheap (Expendable)&quot;">​</a></h3><p>The early-game filler. Cheap to produce, dies fast, buys time. Every faction needs something to throw at a wall while real units train.</p><ul><li><strong>Unit class</strong>: <code>MilitiaLight</code></li><li><strong>Behavior</strong>: <code>Swarm</code>, <code>HoldLine</code></li><li><strong>Defense</strong>: <code>Unarmored</code>, <code>Biological</code></li></ul><h3 id="t1-core-line-infantry" tabindex="-1">T1 Core (Line Infantry) <a class="header-anchor" href="#t1-core-line-infantry" aria-label="Permalink to &quot;T1 Core (Line Infantry)&quot;">​</a></h3><p>The backbone. Reliable damage, reasonable survivability, produced in bulk through mid-game. The unit you build the most of.</p><ul><li><strong>Unit class</strong>: <code>CoreLineInfantry</code></li><li><strong>Behavior</strong>: <code>HoldLine</code>, <code>AdvanceFire</code></li><li><strong>Defense</strong>: <code>InfantryArmor</code>, <code>Biological</code></li></ul><h3 id="t2-elite-premium-infantry" tabindex="-1">T2 Elite (Premium Infantry) <a class="header-anchor" href="#t2-elite-premium-infantry" aria-label="Permalink to &quot;T2 Elite (Premium Infantry)&quot;">​</a></h3><p>Expensive but powerful. Used for key engagements, not mass production. Order factions get more value here; Swarm factions get less.</p><ul><li><strong>Unit class</strong>: <code>EliteLineInfantry</code></li><li><strong>Behavior</strong>: <code>AdvanceFire</code></li><li><strong>Defense</strong>: <code>InfantryArmor</code>, <code>Biological</code></li></ul><h3 id="t2-anti-armor" tabindex="-1">T2 Anti-Armor <a class="header-anchor" href="#t2-anti-armor" aria-label="Permalink to &quot;T2 Anti-Armor&quot;">​</a></h3><p>Specialized counter to vehicles and heavy units. Low rate of fire, high single-target damage. Essential for breaking heavy pushes.</p><ul><li><strong>Unit class</strong>: <code>AntiArmor</code></li><li><strong>Behavior</strong>: <code>AntiArmor</code>, <code>HoldLine</code></li><li><strong>Weapon</strong>: <code>ExplosiveAT</code> or <code>MissileGuided</code></li></ul><h3 id="t2-support" tabindex="-1">T2 Support <a class="header-anchor" href="#t2-support" aria-label="Permalink to &quot;T2 Support&quot;">​</a></h3><p>Suppression fire and area denial. Holds lanes, forces enemies to slow down or take alternate routes. Machine guns, heavy blasters, recoilless rifles.</p><ul><li><strong>Unit class</strong>: <code>HeavyInfantry</code></li><li><strong>Behavior</strong>: <code>HoldLine</code>, <code>MoralePressure</code></li><li><strong>Weapon</strong>: <code>SuppressionWeapon</code></li></ul><h3 id="t2-recon" tabindex="-1">T2 Recon <a class="header-anchor" href="#t2-recon" aria-label="Permalink to &quot;T2 Recon&quot;">​</a></h3><p>Fast, fragile scout. Provides vision, spots for artillery, harasses flanks. Drones in modern theme, speeder bikes in Star Wars.</p><ul><li><strong>Unit class</strong>: <code>Recon</code></li><li><strong>Behavior</strong>: <code>Kite</code></li><li><strong>Defense</strong>: <code>Unarmored</code></li></ul><h3 id="t3-light-vehicle" tabindex="-1">T3 Light Vehicle <a class="header-anchor" href="#t3-light-vehicle" aria-label="Permalink to &quot;T3 Light Vehicle&quot;">​</a></h3><p>Fast vehicle for flanking, pursuit, and exploitation. Technicals, IFVs, AT-RTs, spider droids.</p><ul><li><strong>Unit class</strong>: <code>FastVehicle</code></li><li><strong>Behavior</strong>: <code>AdvanceFire</code>, <code>Charge</code></li><li><strong>Defense</strong>: <code>Mechanical</code></li></ul><h3 id="t3-heavy-vehicle" tabindex="-1">T3 Heavy Vehicle <a class="header-anchor" href="#t3-heavy-vehicle" aria-label="Permalink to &quot;T3 Heavy Vehicle&quot;">​</a></h3><p>Main battle tank or equivalent. High armor, high damage, slow. Anchors defensive lines or spearheads assaults.</p><ul><li><strong>Unit class</strong>: <code>MainBattleVehicle</code></li><li><strong>Behavior</strong>: <code>AdvanceFire</code>, <code>AntiArmor</code></li><li><strong>Defense</strong>: <code>HeavyArmor</code>, <code>Mechanical</code></li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Guerrilla faction does not have a heavy vehicle. Their asymmetric doctrine relies on RPG teams and ambushes instead.</p></div><h3 id="t3-artillery" tabindex="-1">T3 Artillery <a class="header-anchor" href="#t3-artillery" aria-label="Permalink to &quot;T3 Artillery&quot;">​</a></h3><p>Long-range area bombardment. Expensive, devastating against formations. MLRS, howitzers, shelling droids, SP batteries.</p><ul><li><strong>Unit class</strong>: <code>Artillery</code></li><li><strong>Behavior</strong>: <code>SiegePriority</code></li><li><strong>Defense</strong>: <code>Mechanical</code></li></ul><h3 id="defense-1-light-static" tabindex="-1">Defense 1 (Light Static) <a class="header-anchor" href="#defense-1-light-static" aria-label="Permalink to &quot;Defense 1 (Light Static)&quot;">​</a></h3><p>Basic defensive emplacement. MG nests, blaster towers, bunkers. Covers approaches and slows enemy advances.</p><ul><li><strong>Unit class</strong>: <code>StaticMG</code></li><li><strong>Defense</strong>: <code>Fortified</code></li></ul><h3 id="defense-2-heavy-static" tabindex="-1">Defense 2 (Heavy Static) <a class="header-anchor" href="#defense-2-heavy-static" aria-label="Permalink to &quot;Defense 2 (Heavy Static)&quot;">​</a></h3><p>Anti-armor or heavy defensive position. Missile emplacements, turbolasers, AT positions. Stops heavy pushes.</p><ul><li><strong>Unit class</strong>: <code>StaticAT</code></li><li><strong>Defense</strong>: <code>Fortified</code></li></ul><h3 id="commander" tabindex="-1">Commander <a class="header-anchor" href="#commander" aria-label="Permalink to &quot;Commander&quot;">​</a></h3><p>Hero or command unit that provides buffs to nearby units. Jedi, officers, commissars, field emirs. One per army, powerful but vulnerable.</p><ul><li><strong>Unit class</strong>: <code>HeroCommander</code></li><li><strong>Behavior</strong>: <code>HoldLine</code></li><li><strong>Defense</strong>: <code>Heroic</code></li></ul><h3 id="spike-unit" tabindex="-1">Spike Unit <a class="header-anchor" href="#spike-unit" aria-label="Permalink to &quot;Spike Unit&quot;">​</a></h3><p>Faction signature capability. Something unique that breaks the normal rules — droideka shields, drone strikes, thermobaric weapons, ambush waves.</p><ul><li><strong>Unit class</strong>: <code>ShieldedElite</code> or varies by faction</li><li><strong>Behavior</strong>: Faction-specific</li></ul>',47)])])}const p=e(i,[["render",o]]);export{m as __pageData,p as default};
